  (current.id ? `https://drive.google.com/file/d/${current.id}/view?usp=sharing` : "") ||
  report.drive_link ||
  report.webViewLink ||
  "";

function pad2(n) {
  return String(n).padStart(2, "0");
}

function getThaiTime() {
  if (report.scan_time_th) return report.scan_time_th;

  const now = new Date();
  const th = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Bangkok" }));
  const dd = pad2(th.getDate());
  const mm = pad2(th.getMonth() + 1);
  const yyyy = th.getFullYear() + 543;
  const hh = pad2(th.getHours());
  const mi = pad2(th.getMinutes());
  const ss = pad2(th.getSeconds());

  return `${dd}/${mm}/${yyyy} ${hh}:${mi}:${ss}`;
}

function toNumber(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

const critical = toNumber(report.critical_count || report.risk_distribution?.CRITICAL || 0);
const high = toNumber(report.high_count || report.risk_distribution?.HIGH || 0);
const medium = toNumber(report.medium_count || report.risk_distribution?.MEDIUM || 0);
const low = toNumber(report.low_count || report.risk_distribution?.LOW || 0);

const totalHosts = toNumber(report.total_hosts || 0);
const totalFindings = toNumber(report.total_findings || 0);
const avgRiskScore = toNumber(report.avg_risk_score || 0);
const avgSecurityScore = toNumber(report.avg_security_score || 0);
