// CODE | Filter Latest Scan
// Mode: Run Once for All Items

function minuteKey(v) {
  const s = String(v || '').trim();
  // เอาถึงระดับนาที เช่น 2026-03-11T21:55
  return s ? s.slice(0, 16) : '';
}

// หา minute ล่าสุด
let latestMinute = '';

for (const item of items) {
  const key = minuteKey(item.json.detected_at);
  if (key && key > latestMinute) {
    latestMinute = key;
  }
}

// คืนทุก item ที่อยู่ใน minute เดียวกัน
return items.filter(item => minuteKey(item.json.detected_at) === latestMinute);

// Code: Build HTML Report L4 (Professional Plus v2 / Executive Summary First / CVE+KEV Aware / Binary-safe / Run Once for All Items)
// For: Level 4 - Report & Notify
// Input: aggregated findings from Level 3
// Output: binary.html (index.html) for Gotenberg

// ---------------- helpers ----------------
function pad2(n) { return String(n).padStart(2, "0"); }

function esc(s) {
  return String(s ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function safeArr(v) { return Array.isArray(v) ? v : []; }

function toNumber(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

function upper(s) {
  return String(s ?? "").toUpperCase();
}

function uniq(arr) {
  return [...new Set(safeArr(arr).filter(Boolean))];
}

function shortText(s, max = 120) {
  const t = String(s ?? "");
  return t.length > max ? `${t.slice(0, max)}...` : t;
}

function displayLevel(r) {
  return upper(r.threat_level || r.rule_risk || r.risk_level || "UNKNOWN");
}

function severityRank(level) {
  const L = upper(level);
  if (L === "CRITICAL" || L === "SEVERE") return 4;
  if (L === "HIGH") return 3;
  if (L === "MEDIUM" || L === "MODERATE") return 2;
  if (L === "LOW") return 1;
  return 0;
}

function riskColor(level) {
  const L = upper(level);
  if (L === "CRITICAL" || L === "SEVERE") return { bg: "#FFE5E5", bd: "#FF5A5A", fg: "#7D0000", soft: "#FFF5F5" };
  if (L === "HIGH") return { bg: "#FFF1E6", bd: "#FF8A3D", fg: "#7A2F00", soft: "#FFF8F2" };
  if (L === "MEDIUM" || L === "MODERATE") return { bg: "#FFF7DB", bd: "#FFCC42", fg: "#6A4B00", soft: "#FFFDF4" };
  if (L === "LOW") return { bg: "#E9FFF0", bd: "#4CC26A", fg: "#0B5A1A", soft: "#F5FFF8" };
  return { bg: "#F2F4F7", bd: "#D0D5DD", fg: "#344054", soft: "#FAFBFC" };
}

function riskBadge(level) {
  const L = upper(level || "UNKNOWN");
  const c = riskColor(L);
  return `<span class="badge" style="background:${c.bg};border-color:${c.bd};color:${c.fg}">${esc(L)}</span>`;
}

function buildServiceLabel(r) {
  const serviceName = String(r.service_name || "").trim();
  const service = String(r.service || "").trim();
  return serviceName || service || "-";
}

function buildCveLabel(r) {
  const top = String(r.top_cve_id || "").trim();
  if (top) return top;

  const raw = String(r.cve_ids || "").trim();
  if (!raw) return "-";

  const first = raw.split(",").map(x => x.trim()).filter(Boolean)[0];
  return first || "-";
}

function formatHostTopFinding(arr) {
  const a = safeArr(arr);
  if (!a.length) return "-";

  const top = a
    .slice()
    .sort((x, y) => {
      const sr = severityRank(displayLevel(y)) - severityRank(displayLevel(x));
      if (sr !== 0) return sr;
      return toNumber(y.security_score, toNumber(y.risk_score, 0)) - toNumber(x.security_score, toNumber(x.risk_score, 0));
    })[0];

  const svc = buildServiceLabel(top);
  const port = top.port ?? "-";
  const risk = displayLevel(top);
  const cve = buildCveLabel(top);
  return `${svc}:${port} (${risk}${cve !== "-" ? ` | ${cve}` : ""})`;
}

function avg(arr) {
  const a = safeArr(arr).map(x => Number(x)).filter(x => Number.isFinite(x));
  if (!a.length) return 0;
  return a.reduce((s, n) => s + n, 0) / a.length;
}

function getOverallThreat(counts) {
  if ((counts.CRITICAL || 0) > 0) return "CRITICAL";
  if ((counts.HIGH || 0) > 0) return "HIGH";
  if ((counts.MEDIUM || 0) > 0) return "MEDIUM";
  if ((counts.LOW || 0) > 0) return "LOW";
  return "UNKNOWN";
}

function buildSection(title, innerHtml, extraClass = "") {
  return `
    <section class="section-block ${extraClass}">
      <div class="section-title">${title}</div>
      ${innerHtml}
    </section>
  `;
}

// ---------- find binary source item safely ----------
const firstBinaryItem = items.find(i => i.binary && typeof i.binary === "object") || null;
const bin0 = firstBinaryItem?.binary || {};

// ---------- Binary -> base64 ----------
async function binaryToBase64(prop, fallbackMime = "image/png") {
  const binaryIndex = items.findIndex(i => i.binary && i.binary[prop]);
  if (binaryIndex === -1) return { base64: "", mime: fallbackMime, via: "none" };

  const b = items[binaryIndex].binary[prop];
  const mime = b?.mimeType || fallbackMime;

  try {
    const buffer = await this.helpers.getBinaryDataBuffer(binaryIndex, prop);
    if (!buffer) return { base64: "", mime, via: "no_buffer" };
    return { base64: buffer.toString("base64"), mime, via: "helper" };
  } catch (e) {
    const direct = b?.data || "";
    if (direct && typeof direct === "string" && direct.length > 1000) {
      return { base64: direct, mime, via: "direct" };
    }
    return { base64: "", mime, via: "error" };
  }
}

// -------------- Time (Thailand) --------------
const now = new Date(Date.now() + 7 * 60 * 60 * 1000);
const yyyy = now.getUTCFullYear();
const mm = pad2(now.getUTCMonth() + 1);
const dd = pad2(now.getUTCDate());
const hh = pad2(now.getUTCHours());
const mi = pad2(now.getUTCMinutes());
const ss = pad2(now.getUTCSeconds());

const scanTimeTH = `${dd}/${mm}/${yyyy + 543} ${hh}:${mi}:${ss}`;
const scannedAtISO = `${yyyy}-${mm}-${dd}T${hh}:${mi}:${ss}+07:00`;
const reportName = `SmartInfra_VA_L4_ProfessionalPlus_v2_${yyyy}-${mm}-${dd}_${hh}${mi}${ss}`;

// -------------- Load logo/signature --------------
const logoRes = await binaryToBase64.call(this, "logo", "image/png");
const sigRes = await binaryToBase64.call(this, "signature", "image/png");

const logoDataUri = logoRes.base64 ? `data:${logoRes.mime};base64,${logoRes.base64}` : "";
const signDataUri = sigRes.base64 ? `data:${sigRes.mime};base64,${sigRes.base64}` : "";

// -------------- Collect findings --------------
const findings = items
  .map(i => i.json || {})
  .filter(r =>
    r &&
    (
      r.ip ||
      r.finding_key ||
      r.row_key ||
      r.finding ||
      r.rule_risk ||
      r.risk_level ||
      r.threat_level
    )
  );

// -------------- Aggregate counts --------------
const totalFindings = findings.length;
const uniqueHosts = uniq(findings.map(r => String(r.ip || "").trim()).filter(Boolean));
const totalHosts = uniqueHosts.length;

const counts = { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0, UNKNOWN: 0 };
let totalRiskScore = 0;
let totalSecurityScore = 0;
let securityScoreCount = 0;
let kevCount = 0;
let cveDetectedCount = 0;

for (const r of findings) {
  const lvl = displayLevel(r);
  if (counts[lvl] !== undefined) counts[lvl] += 1;
  else counts.UNKNOWN += 1;

  totalRiskScore += toNumber(r.risk_score, 0);

  const ssNum = toNumber(r.security_score, NaN);
  if (Number.isFinite(ssNum)) {
    totalSecurityScore += ssNum;
    securityScoreCount += 1;
  }

  if (r.kev_exploited) kevCount += 1;
  if (r.cve_found) cveDetectedCount += 1;
}

const avgRiskScore = totalFindings ? (totalRiskScore / totalFindings) : 0;
const avgSecurityScore = securityScoreCount ? (totalSecurityScore / securityScoreCount) : 0;

// -------------- Overall Security Grade --------------
let overallSecurityGrade = "F";
if (avgSecurityScore >= 90) overallSecurityGrade = "A";
else if (avgSecurityScore >= 75) overallSecurityGrade = "B";
else if (avgSecurityScore >= 60) overallSecurityGrade = "C";
else if (avgSecurityScore >= 40) overallSecurityGrade = "D";

const overallThreat = getOverallThreat(counts);
const overallThreatColor = riskColor(overallThreat);

let postureText = "System posture appears stable with low immediate exposure.";
if (overallThreat === "CRITICAL") postureText = "Immediate action required. Critical-risk findings detected in the current attack surface.";
else if (overallThreat === "HIGH") postureText = "Elevated risk posture. High-risk exposures should be prioritized for remediation.";
else if (overallThreat === "MEDIUM") postureText = "Moderate exposure detected. Corrective controls and hardening are recommended.";
else if (overallThreat === "LOW") postureText = "Low-risk exposures detected. Maintain patching and service hardening discipline.";
else postureText = "No significant findings were detected in the current dataset.";

// -------------- Group by host --------------
const hostMap = new Map();

for (const r of findings) {
  const ip = String(r.ip || "-").trim() || "-";

  if (!hostMap.has(ip)) {
    hostMap.set(ip, {
      ip,
      findings: [],
      ports: new Set(),
      max_risk_level: "LOW",
      max_risk_score: 0,
      max_security_score: 0,
      critical_count: 0,
      high_count: 0,
      medium_count: 0,
      low_count: 0,
      kev_count: 0,
      cve_count: 0
    });
  }

  const h = hostMap.get(ip);
  h.findings.push(r);

  if (r.port !== undefined && r.port !== null && String(r.port) !== "") {
    h.ports.add(String(r.port));
  }

  const lvl = displayLevel(r);
  if (lvl === "CRITICAL") h.critical_count += 1;
  else if (lvl === "HIGH") h.high_count += 1;
  else if (lvl === "MEDIUM") h.medium_count += 1;
  else if (lvl === "LOW") h.low_count += 1;

  if (r.kev_exploited) h.kev_count += 1;
  if (r.cve_found) h.cve_count += 1;

  const rs = toNumber(r.risk_score, 0);
  const ssNum = toNumber(r.security_score, 0);

  if (
    severityRank(lvl) > severityRank(h.max_risk_level) ||
    (severityRank(lvl) === severityRank(h.max_risk_level) && ssNum > h.max_security_score)
  ) {
    h.max_risk_level = lvl;
    h.max_risk_score = rs;
    h.max_security_score = ssNum;
  }
}

const hosts = [...hostMap.values()];

// -------------- Top 5 Hosts by Risk --------------
const top5Hosts = hosts
  .map(h => ({
    ...h,
    ports_display: [...h.ports].sort((a, b) => Number(a) - Number(b)).join(", "),
    finding_count: h.findings.length,
    top_finding: formatHostTopFinding(h.findings),
    avg_security_score: avg(h.findings.map(x => toNumber(x.security_score, 0)))
  }))
  .sort((a, b) => {
    const sr = severityRank(b.max_risk_level) - severityRank(a.max_risk_level);
    if (sr !== 0) return sr;
    return b.max_security_score - a.max_security_score;
  })
  .slice(0, 5);

// -------------- Top Findings --------------
const top10Findings = findings
  .slice()
  .sort((a, b) => {
    const sr = severityRank(displayLevel(b)) - severityRank(displayLevel(a));
    if (sr !== 0) return sr;
    return toNumber(b.security_score, toNumber(b.risk_score, 0)) - toNumber(a.security_score, toNumber(a.risk_score, 0));
  })
  .slice(0, 10);

// -------------- Top CVE / KEV Summary --------------
const topCveRows = findings
  .filter(r => r.cve_found || r.kev_exploited)
  .slice()
  .sort((a, b) => {
    if (Boolean(b.kev_exploited) !== Boolean(a.kev_exploited)) {
      return Number(Boolean(b.kev_exploited)) - Number(Boolean(a.kev_exploited));
    }
    return toNumber(b.max_cvss_score, 0) - toNumber(a.max_cvss_score, 0);
  })
  .slice(0, 10)
  .map(r => `
    <tr>
      <td class="cell-host">${esc(r.ip || "-")}</td>
      <td class="cell-center mono">${esc(r.port ?? "-")}</td>
      <td class="cell-left">${esc(buildServiceLabel(r))}</td>
      <td class="cell-left small mono">${esc(buildCveLabel(r))}</td>
      <td class="cell-center mono">${esc(toNumber(r.max_cvss_score, 0).toFixed(1))}</td>
      <td class="cell-center">${r.kev_exploited ? `<span class="badge badge-critical">KEV</span>` : "-"}</td>
      <td class="cell-left small">${esc(shortText(r.top_cve_description || r.finding || "-", 130))}</td>
    </tr>
  `)
  .join("");

// -------------- Recommendations by host (Top 5) --------------
let remediationRows = "";

for (const h of top5Hosts) {
  const recs = uniq(h.findings.map(x => String(x.recommendation || "").trim()).filter(Boolean));
  const issues = h.findings
    .slice()
    .sort((a, b) => {
      const sr = severityRank(displayLevel(b)) - severityRank(displayLevel(a));
      if (sr !== 0) return sr;
      return toNumber(b.security_score, toNumber(b.risk_score, 0)) - toNumber(a.security_score, toNumber(a.risk_score, 0));
    })
    .slice(0, 5)
    .map(x => {
      const svc = buildServiceLabel(x);
      const cve = buildCveLabel(x);
      return `<li><b>${esc(`${svc}:${x.port ?? "-"}`)}:</b> ${esc(x.finding || "-")}${cve !== "-" ? ` <span class="mono">[${esc(cve)}]</span>` : ""}</li>`;
    })
    .join("");

  const acts = recs.length
    ? recs.slice(0, 5).map(x => `<li>${esc(x)}</li>`).join("")
    : `<li>อัปเดตแพตช์, จำกัดการเข้าถึง, ตรวจสอบ hardening, logging และ access control ของบริการที่เปิดใช้งาน</li>`;

  remediationRows += `
