      <td class="cell-center mono">${esc(h.max_security_score.toFixed(1))}</td>
      <td class="cell-left small"><ul class="rec">${issues || "<li>-</li>"}</ul></td>
      <td class="cell-left small"><ul class="rec">${acts}</ul></td>
    </tr>
  `;
}

