    .cols-rem th:nth-child(5){ width: 36%; }   /* Recommended Actions */

    /* appendix better layout */
    .appendix-table{
      overflow: visible;
    }

    .appendix-risk-table{
      width:100%;
      border-collapse: collapse;
      table-layout: auto;
      background:#fff;
    }

    .appendix-risk-table thead{
      display: table-header-group;
    }

    .appendix-risk-table th{
      background: var(--brand2);
      color:#fff;
      font-size:12px;
      padding:10px 8px;
      text-align:center;
      font-weight:800;
      white-space: nowrap;
      border-bottom: 1px solid #184364;
    }

    .appendix-risk-table td{
      border-top:1px solid var(--line);
      padding:10px 9px;
      font-size:11.5px;
      vertical-align: top;
      word-break: normal;
      overflow-wrap: break-word;
      white-space: normal;
      line-height: 1.45;
    }

    .appendix-risk-table tbody tr{
      page-break-inside: avoid;
      break-inside: avoid;
    }

    .appendix-risk-table tbody tr:nth-child(even){
      background:#FBFDFF;
    }

    .appendix-risk-table th:nth-child(1),
    .appendix-risk-table td:nth-child(1){ width: 12%; }

    .appendix-risk-table th:nth-child(2),
    .appendix-risk-table td:nth-child(2){ width: 6%; }

    .appendix-risk-table th:nth-child(3),
    .appendix-risk-table td:nth-child(3){ width: 6%; }

    .appendix-risk-table th:nth-child(4),
    .appendix-risk-table td:nth-child(4){ width: 10%; }

    .appendix-risk-table th:nth-child(5),
    .appendix-risk-table td:nth-child(5){ width: 9%; }

    .appendix-risk-table th:nth-child(6),
    .appendix-risk-table td:nth-child(6){ width: 7%; }

    .appendix-risk-table th:nth-child(7),
    .appendix-risk-table td:nth-child(7){ width: 12%; }

    .appendix-risk-table th:nth-child(8),
    .appendix-risk-table td:nth-child(8){ width: 18%; }

    .appendix-risk-table th:nth-child(9),
    .appendix-risk-table td:nth-child(9){ width: 20%; }

    .top, .grid, .card, .section-block, .footer {
      orphans: 3;
      widows: 3;
    }
  </style>
</head>

