// Output as binary.html for Gotenberg
const htmlBuffer = Buffer.from(html, "utf8");

return [{
  json: {
    report_name: reportName,
    scanned_at: scannedAtISO,
    scan_time_th: scanTimeTH,
    total_hosts: totalHosts,
    total_findings: totalFindings,
    avg_risk_score: Number(avgRiskScore.toFixed(1)),
    avg_security_score: Number(avgSecurityScore.toFixed(1)),
    security_grade: overallSecurityGrade,
    overall_threat: overallThreat,
    critical_count: counts.CRITICAL,
    high_count: counts.HIGH,
    medium_count: counts.MEDIUM,
    low_count: counts.LOW,
    unknown_count: counts.UNKNOWN,
    cve_count: cveDetectedCount,
    kev_count: kevCount,
    risk_distribution: counts,
    _debug_logo_via: logoRes.via,
    _debug_sig_via: sigRes.via,
    _debug_logo_len: (logoRes.base64 || "").length,
    _debug_sig_len: (sigRes.base64 || "").length
  },
  binary: {
    ...(bin0 || {}),
    html: {
      data: htmlBuffer.toString("base64"),
      mimeType: "text/html",
      fileName: "index.html",
    }
  }
}];

// Code: Build LINE Message
// Input: current item + report summary from "Code | Build HTML Report"

const current = items[0]?.json || {};

let report = {};
try {
  report = $('Code | Build HTML Report').all()[0]?.json || {};
} catch (e) {
  report = {};
}

const driveLink =
  current.drive_link ||
  current.webViewLink ||
  (current.id ? `https://drive.google.com/file/d/${current.id}/view?usp=sharing` : "") ||
  report.drive_link ||
  report.webViewLink ||
  "";

function pad2(n) {
  return String(n).padStart(2, "0");
}

function getThaiTime() {
  if (report.scan_time_th) return report.scan_time_th;

  const now = new Date();
  const th = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Bangkok" }));
  const dd = pad2(th.getDate());
  const mm = pad2(th.getMonth() + 1);
  const yyyy = th.getFullYear() + 543;
  const hh = pad2(th.getHours());
  const mi = pad2(th.getMinutes());
  const ss = pad2(th.getSeconds());

  return `${dd}/${mm}/${yyyy} ${hh}:${mi}:${ss}`;
}

const critical = Number(report.critical_count || report.risk_distribution?.CRITICAL || 0);
const high = Number(report.high_count || report.risk_distribution?.HIGH || 0);
const medium = Number(report.medium_count || report.risk_distribution?.MEDIUM || 0);
const low = Number(report.low_count || report.risk_distribution?.LOW || 0);

const totalHosts = Number(report.total_hosts || 0);
const totalFindings = Number(report.total_findings || 0);
const avgRiskScore = Number(report.avg_risk_score || 0);
const avgSecurityScore = Number(report.avg_security_score || 0);
const securityGrade = report.security_grade || "-";
const kevCount = Number(report.kev_count || 0);
const cveCount = Number(report.cve_count || 0);

// สถานะระบบ
let systemStatus = "NORMAL";
if (critical > 0) systemStatus = "EMERGENCY";
else if (high > 0) systemStatus = "ATTENTION";
else if (medium > 0) systemStatus = "REVIEW";

// สรุประดับแจ้งเตือน
let alertLabel = "NORMAL";
let alertIcon = "🟢";

if (critical > 0) {
  alertLabel = "CRITICAL";
  alertIcon = "🚨";
} else if (high > 0) {
  alertLabel = "HIGH";
  alertIcon = "⚠️";
} else if (medium > 0) {
  alertLabel = "MEDIUM";
  alertIcon = "🟡";
}

// Build LINE message
let msg = "";
msg += `🛡️ SmartInfra VA Alert (Level 4)\n`;
msg += `🕒 ${getThaiTime()}\n\n`;

msg += `${alertIcon} Alert Level: ${alertLabel}\n`;
msg += `📍 System Status: ${systemStatus}\n\n`;

msg += `🖥 Hosts scanned: ${totalHosts}\n`;
msg += `📌 Total findings: ${totalFindings}\n`;
msg += `📈 Avg Risk Score: ${avgRiskScore.toFixed(1)}\n`;
msg += `🔐 Avg Security Score: ${avgSecurityScore.toFixed(1)}\n`;
msg += `🏷 Security Grade: ${securityGrade}\n\n`;

msg += `📊 Risk Distribution\n`;
msg += `🟥 CRITICAL: ${critical}\n`;
msg += `🟧 HIGH: ${high}\n`;
msg += `🟨 MEDIUM: ${medium}\n`;
msg += `🟩 LOW: ${low}\n`;
msg += `🦠 CVE: ${cveCount}\n`;
msg += `🔥 KEV: ${kevCount}\n`;

if ((critical + high) > 0) {
  msg += `\n🚨 High/Critical Total: ${critical + high}\n`;
}

if (driveLink) {
  msg += `\n📄 Report (PDF):\n${driveLink}\n`;
}

return [{
  json: {
    ...current,
    ...report,
    drive_link: driveLink,
    alert_level_label: alertLabel,
    system_status: systemStatus,
    line_message: msg
  },
  binary: items[0]?.binary
}];
